import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"闲钱理财","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/idle-cash.md","filePath":"zh-CN/funds-and-wealth/idle-cash.md"}'),h={name:"funds-and-wealth/idle-cash.md"};function l(o,t,i,n,s,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="闲钱理财" tabindex="-1">闲钱理财 <a class="header-anchor" href="#闲钱理财" aria-label="Permalink to &quot;闲钱理财&quot;">​</a></h1><p>闲钱理财是长桥为短期闲置资金提供的理财服务，分为「余额通」和「进阶理财」两个层次，满足不同风险偏好和流动性需求。入口在「市场」→「财富」→「闲钱理财」。</p><h2 id="余额通" tabindex="-1">余额通 <a class="header-anchor" href="#余额通" aria-label="Permalink to &quot;余额通&quot;">​</a></h2><p>余额通采用 <strong>T 日灵活申赎</strong>机制，申购和赎回均在当日完成，资金随时可用。主要对接货币市场基金，风险较低。</p><h3 id="主要货币基金产品示例" tabindex="-1">主要货币基金产品示例 <a class="header-anchor" href="#主要货币基金产品示例" aria-label="Permalink to &quot;主要货币基金产品示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>基金名称</th><th>计价货币</th><th>近一年收益（参考）</th></tr></thead><tbody><tr><td>高腾微金美元货币基金 A USD Accumulation</td><td>USD</td><td>+4.12%</td></tr><tr><td>泰康开泰港元货币基金 A Acc</td><td>HKD</td><td>+2.15%</td></tr><tr><td>华夏精选美元货币基金 Class B USD</td><td>USD</td><td>+4.14%</td></tr></tbody></table><blockquote><p>收益数据仅供参考，实际收益以申赎时基金净值为准，过往表现不代表未来收益。</p></blockquote><h2 id="进阶理财" tabindex="-1">进阶理财 <a class="header-anchor" href="#进阶理财" aria-label="Permalink to &quot;进阶理财&quot;">​</a></h2><p>进阶理财提供收益潜力更高的债券型基金，适合风险承受能力稍高、资金不急于使用的投资者。</p><h3 id="主要产品类型" tabindex="-1">主要产品类型 <a class="header-anchor" href="#主要产品类型" aria-label="Permalink to &quot;主要产品类型&quot;">​</a></h3><p><strong>短期债券基金</strong>（中低风险）</p><p>适合追求稳健增值的投资者，存续期较短，流动性相对较好。</p><table tabindex="0"><thead><tr><th>基金名称</th><th>计价货币</th><th>风险等级</th><th>近一年收益（参考）</th></tr></thead><tbody><tr><td>泰康开泰海外短期债券基金 A HKD Acc</td><td>HKD</td><td>中低风险</td><td>+5.17%</td></tr><tr><td>泰康开泰海外短期债券基金 A USD Acc</td><td>USD</td><td>中低风险</td><td>+4.45%</td></tr><tr><td>易方达（香港）多元入息债券基金 A Acc HKD</td><td>HKD</td><td>中低风险</td><td>+4.20%</td></tr></tbody></table><p><strong>收益增强债券基金</strong>（中高风险）</p><p>追求更高收益，需承受一定利率或信用风险。</p><table tabindex="0"><thead><tr><th>基金名称</th><th>计价货币</th><th>风险等级</th></tr></thead><tbody><tr><td>易方达（香港）精选债券基金 A HKD Acc</td><td>HKD</td><td>中高风险</td></tr></tbody></table><h2 id="余额通-vs-进阶理财对比" tabindex="-1">余额通 vs 进阶理财对比 <a class="header-anchor" href="#余额通-vs-进阶理财对比" aria-label="Permalink to &quot;余额通 vs 进阶理财对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>余额通</th><th>进阶理财</th></tr></thead><tbody><tr><td>流动性</td><td>T 日申赎，资金当日到账</td><td>按基金赎回规则，通常 T+ 数日</td></tr><tr><td>风险等级</td><td>低</td><td>中低至中高</td></tr><tr><td>适合人群</td><td>随时可能动用的短期资金</td><td>1 个月以上暂不使用的闲置资金</td></tr><tr><td>产品类型</td><td>货币市场基金</td><td>债券型基金</td></tr></tbody></table><h2 id="风险提示与收益参考说明" tabindex="-1">风险提示与收益参考说明 <a class="header-anchor" href="#风险提示与收益参考说明" aria-label="Permalink to &quot;风险提示与收益参考说明&quot;">​</a></h2><ul><li>货币基金和债券基金均有亏损风险，并非保本产品</li><li>进阶理财产品赎回时间不同于余额通，使用前请确认资金使用计划</li><li>历史收益数据仅作参考，不构成收益承诺</li><li>具体申赎规则和最新收益数据以产品详情页为准</li></ul>',20)])])}const p=d(h,[["render",l]]);export{u as __pageData,p as default};
